```javascript
// stores/session-store.js
const path = require('path');
const { readJSON, writeJSON } = require('./json-store');  // 统一原子读写

const SESSIONS_FILE = 'ccl-sessions.json';

function loadSessions() { return readJSON(path.join(b(), SESSIONS_FILE)) || []; }
function saveSessions(sessions) { writeJSON(path.join(b(), SESSIONS_FILE), sessions); }
function updateSession(index, updates) {
  const sessions = loadSessions();
  Object.assign(sessions[index], updates);
  saveSessions(sessions);
}

module.exports = { loadSessions, saveSessions, updateSession };
```

